class Solution:
    def recoverOrder(self, order, friends):
        pos = {v: i for i, v in enumerate(order)}
        return sorted(friends, key=lambda f: pos[f])

solutions.python:
class Solution:
    def recoverOrder(self, order, friends):
        fset = set(friends)
        return [v for v in order if v in fset]

